    26â†’function UrgencyChip({ urgency }: { urgency: string }) {
    27â†’  const u = urgency.toLowerCase();
    28â†’  const style = URGENCY_COLORS[u];
    29â†’  if (!style) return null;
    30â†’  return (
    31â†’    <span
    32â†’      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
    33â†’      style={{ backgroundColor: style.bg, color: style.text }}
    34â†’    >
    35â†’      {urgency}
    36â†’    </span>
    37â†’  );
    38â†’}
    39â†’
    40â†’/* ---------- Helpers ---------- */
    41â†’
    42â†’const PER_PAGE = 15;
    43â†’
    44â†’/* ---------- Main component ---------- */
    45â†’
    46â†’export function SemanticReleasesList() {
    47â†’  return (
    48â†’    <Suspense>
