    54â†’function SemanticReleasesListInner() {
    55â†’  const searchParams = useSearchParams();
    56â†’  const initialProject = searchParams.get("project") ?? "all";
    57â†’  const [page, setPage] = useState(1);
    58â†’  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    59â†’  const [deletingId, setDeletingId] = useState<string | null>(null);
    60â†’
    61â†’  /* Fetch projects for the filter dropdown */
    62â†’  const { data: projectsData } = useSWR("projects-for-sr-filter", () =>
    63â†’    projectsApi.list(1, 100)
    64â†’  );
    65â†’
    66â†’  /* Fetch semantic releases â€” scoped by project or all */
    67â†’  const { data: scopedData, isLoading: scopedLoading, mutate: mutateScopedData } = useSWR(
    68â†’    projectFilter !== "all" ? ["sr-scoped", page, projectFilter] : null,
    69â†’    () => srApi.list(projectFilter, page, PER_PAGE)
    70â†’  );
    71â†’
    72â†’  const { data: allData, isLoading: allLoading, mutate: mutateAllData } = useSWR(
    73â†’    projectFilter === "all" ? ["sr-all", page] : null,
    74â†’    () => srApi.listAll(page, PER_PAGE)
    75â†’  );
    76â†’
    77â†’  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
    78â†’  const releases: SemanticRelease[] =
    79â†’    projectFilter !== "all"
