    87â†’  const total = activeData?.meta?.total ?? 0;
    88â†’  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
    89â†’  const startRow = (page - 1) * PER_PAGE + 1;
    90â†’  const endRow = Math.min(page * PER_PAGE, total);
    91â†’
    92â†’  return (
    93â†’    <div className="space-y-6 fade-in">
    94â†’      {/* Page title */}
    95â†’      <h1
    96â†’        style={{
    97â†’          fontFamily: "var(--font-fraunces)",
    98â†’          fontSize: "24px",
    99â†’          fontWeight: 700,
   100â†’          color: "#111113",
   101â†’        }}
   102â†’      >
   103â†’        Semantic Releases
   104â†’      </h1>
   105â†’
   106â†’      {/* Project filter */}
   107â†’      <div>
   108â†’        <select
   109â†’          value={projectFilter}
   110â†’          onChange={(e) => {
   111â†’            setProjectFilter(e.target.value);
   112â†’            setPage(1);
   113â†’          }}
   114â†’          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
   115â†’          style={{
   116â†’            fontFamily: "var(--font-dm-sans)",
   117â†’            fontSize: "13px",
   118â†’            color: "#111113",
   119â†’            border: "1px solid #e8e8e5",
   120â†’          }}
   121â†’          onFocus={(e) =>
   122â†’            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   123â†’          }
   124â†’          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   125â†’        >
   126â†’          <option value="all">All Projects</option>
   127â†’          {projectsData?.data.map((p: Project) => (
   128â†’            <option key={p.id} value={p.id}>
   129â†’              {p.name}
   130â†’            </option>
   131â†’          ))}
   132â†’        </select>
   133â†’      </div>
   134â†’
   135â†’      {/* Table card */}
   136â†’      <div
   137â†’        className="overflow-hidden rounded-lg bg-white"
   138â†’        style={{ border: "1px solid #e8e8e5" }}
   139â†’      >
   140â†’        {isLoading ? (
   141â†’          <div
   142â†’            className="py-16 text-center"
   143â†’            style={{
   144â†’              fontFamily: "var(--font-dm-sans)",
   145â†’              fontSize: "13px",
   146â†’              color: "#6b7280",
   147â†’            }}
   148â†’          >
   149â†’            Loading...
   150â†’          </div>
   151â†’        ) : releases.length === 0 ? (
   152â†’          <div className="py-16 text-center">
   153â†’            <p
   154â†’              style={{
   155â†’                fontFamily: "var(--font-fraunces)",
   156â†’                fontStyle: "italic",
   157â†’                fontSize: "15px",
   158â†’                color: "#9ca3af",
   159â†’              }}
   160â†’            >
   161â†’              No semantic releases yet
   162â†’            </p>
   163â†’          </div>
   164â†’        ) : (
   165â†’          <table className="w-full">
   166â†’            <thead>
   167â†’              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   168â†’                {["Project", "Version", "Status", "Urgency", "Age", ""].map(
   169â†’                  (col) => (
   170â†’                    <th
   171â†’                      key={col}
   172â†’                      className="px-4 py-3 text-left"
   173â†’                      style={{
   174â†’                        fontFamily: "var(--font-dm-sans)",
   175â†’                        fontSize: "11px",
   176â†’                        fontWeight: 600,
   177â†’                        textTransform: "uppercase" as const,
   178â†’                        letterSpacing: "0.08em",
   179â†’                        color: "#9ca3af",
   180â†’                      }}
   181â†’                    >
   182â†’                      {col}
   183â†’                    </th>
   184â†’                  )
   185â†’                )}
   186â†’              </tr>
   187â†’            </thead>
   188â†’            <tbody>
   189â†’              {releases.map((sr) => {
   190â†’                return (
   191â†’                  <tr
   192â†’                    key={sr.id}
   193â†’                    className="transition-colors hover:bg-[#fafaf9]"
   194â†’                    style={{ borderBottom: "1px solid #e8e8e5" }}
   195â†’                  >
   196â†’                    {/* Project */}
   197â†’                    <td className="px-4 py-3">
   198â†’                      {sr.project_name ? (
   199â†’                        <Link
   200â†’                          href={`/projects/${sr.project_id}`}
   201â†’                          className="hover:underline"
   202â†’                          style={{
   203â†’                            fontFamily: "var(--font-dm-sans)",
   204â†’                            fontSize: "13px",
   205â†’                            color: "#111113",
   206â†’                            fontWeight: 500,
   207â†’                          }}
   208â†’                        >
   209â†’                          {sr.project_name}
   210â†’                        </Link>
   211â†’                      ) : (
   212â†’                        <span
   213â†’                          style={{
   214â†’                            fontFamily: "var(--font-dm-sans)",
   215â†’                            fontSize: "13px",
   216â†’                            color: "#9ca3af",
   217â†’                          }}
   218â†’                        >
   219â†’                          {"\u2014"}
   220â†’                        </span>
   221â†’                      )}
   222â†’                    </td>
   223â†’
   224â†’                    {/* Version */}
   225â†’                    <td className="px-4 py-3">
   226â†’                      <Link href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}>
   227â†’                        <VersionChip version={sr.version} />
   228â†’                      </Link>
   229â†’                    </td>
   230â†’
   231â†’                    {/* Status */}
   232â†’                    <td className="px-4 py-3">
   233â†’                      <span
   234â†’                        className="text-[13px] font-medium"
   235â†’                        style={{
   236â†’                          fontFamily: "var(--font-dm-sans)",
   237â†’                          color: sr.status === "completed" ? "#16a34a" : "#e8601a",
   238â†’                        }}
   239â†’                      >
   240â†’                        {sr.status}
   241â†’                      </span>
   242â†’                    </td>
   243â†’
   244â†’                    {/* Urgency */}
   245â†’                    <td className="px-4 py-3">
   246â†’                      {sr.report?.urgency ? (
   247â†’                        <UrgencyChip urgency={sr.report.urgency} />
   248â†’                      ) : (
   249â†’                        <span
   250â†’                          style={{
   251â†’                            fontFamily: "var(--font-dm-sans)",
   252â†’                            fontSize: "13px",
   253â†’                            color: "#9ca3af",
   254â†’                          }}
   255â†’                        >
   256â†’                          {"\u2014"}
   257â†’                        </span>
   258â†’                      )}
   259â†’                    </td>
   260â†’
   261â†’                    {/* Age */}
   262â†’                    <td className="px-4 py-3">
   263â†’                      <span
   264â†’                        style={{
   265â†’                          fontFamily: "var(--font-dm-sans)",
   266â†’                          fontSize: "13px",
   267â†’                          color: "#9ca3af",
   268â†’                        }}
   269â†’                      >
   270â†’                        {timeAgo(sr.completed_at ?? sr.created_at)}
   271â†’                      </span>
   272â†’                    </td>
   273â†’
   274â†’                    {/* Delete */}
   275â†’                    <td className="px-4 py-3">
   276â†’                      <button
   277â†’                        onClick={() => setDeletingId(sr.id)}
   278â†’                        className="rounded p-1 transition-colors hover:bg-red-50 hover:text-red-600"
   279â†’                        style={{ color: "#9ca3af" }}
   280â†’                        title="Delete semantic release"
   281â†’                      >
   282â†’                        <Trash2 className="h-4 w-4" />
   283â†’                      </button>
   284â†’                    </td>
   285â†’                  </tr>
   286â†’                );
   287â†’              })}
   288â†’            </tbody>
   289â†’          </table>
   290â†’        )}
   291â†’      </div>
   292â†’
   293â†’      {/* Pagination */}
   294â†’      {total > 0 && (
   295â†’        <div className="flex items-center justify-between">
   296â†’          <span
   297â†’            style={{
   298â†’              fontFamily: "var(--font-dm-sans)",
   299â†’              fontSize: "13px",
   300â†’              color: "#9ca3af",
   301â†’            }}
   302â†’          >
   303â†’            {startRow}&ndash;{endRow} of {total}
   304â†’          </span>
   305â†’          <div className="flex items-center gap-2">
   306â†’            <button
   307â†’              disabled={page <= 1}
   308â†’              onClick={() => setPage(page - 1)}
   309â†’              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   310â†’              style={{
   311â†’                fontFamily: "var(--font-dm-sans)",
   312â†’                fontSize: "13px",
   313â†’                color: "#374151",
   314â†’                border: "1px solid #e8e8e5",
   315â†’              }}
   316â†’            >
   317â†’              Previous
   318â†’            </button>
   319â†’            <button
   320â†’              disabled={page >= totalPages}
   321â†’              onClick={() => setPage(page + 1)}
   322â†’              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   323â†’              style={{
   324â†’                fontFamily: "var(--font-dm-sans)",
   325â†’                fontSize: "13px",
   326â†’                color: "#374151",
   327â†’                border: "1px solid #e8e8e5",
   328â†’              }}
   329â†’            >
   330â†’              Next
   331â†’            </button>
   332â†’          </div>
   333â†’        </div>
   334â†’      )}
   335â†’
   336â†’      {/* Delete confirmation */}
   337â†’      <ConfirmDialog
   338â†’        open={!!deletingId}
   339â†’        onOpenChange={(open) => {
   340â†’          if (!open) setDeletingId(null);
   341â†’        }}
   342â†’        title="Delete Semantic Release"
   343â†’        description="This will permanently delete this semantic release and its report."
   344â†’        onConfirm={async () => {
   345â†’          if (deletingId) {
   346â†’            await srApi.delete(deletingId);
   347â†’            mutateData();
   348â†’          }
   349â†’        }}
   350â†’      />
   351â†’    </div>
   352â†’  );
   353â†’}
