    27â†’
    28â†’function getRiskColors(riskLevel?: string) {
    29â†’  switch (riskLevel?.toUpperCase()) {
    30â†’    case "CRITICAL":
    31â†’      return { border: "#dc2626", bg: "#fff1f2", text: "#991b1b" };
    32â†’    case "HIGH":
    33â†’      return { border: "#d97706", bg: "#fff8f0", text: "#92400e" };
    34â†’    case "MEDIUM":
    35â†’      return { border: "#ca8a04", bg: "#fefce8", text: "#854d0e" };
    36â†’    case "LOW":
    37â†’    default:
    38â†’      return { border: "#16a34a", bg: "#f0fdf4", text: "#166534" };
    39â†’  }
    40â†’}
    41â†’
    42â†’function safeHostname(url: string): string {
    43â†’  try {
    44â†’    return new URL(url).hostname.replace("www.", "");
    45â†’  } catch {
    46â†’    return url;
    47â†’  }
    48â†’}
    49â†’
    50â†’function getDownloadLabel(url: string): { label: string; isDirect: boolean } {
    51â†’  const lower = url.toLowerCase();
    52â†’  const filename = lower.split("/").pop() ?? "";
    53â†’
    54â†’  // Detect platform from common patterns in the URL or filename
    55â†’  const platforms: [RegExp, string][] = [
    56â†’    [/linux.*amd64|amd64.*linux/, "Linux x64"],
    57â†’    [/linux.*arm64|arm64.*linux|linux.*aarch64/, "Linux ARM64"],
    58â†’    [/linux.*386|linux.*i386/, "Linux x86"],
    59â†’    [/darwin.*arm64|arm64.*darwin|macos.*arm64|osx.*arm64/, "macOS ARM64"],
    60â†’    [/darwin.*amd64|amd64.*darwin|macos.*amd64|osx.*amd64/, "macOS x64"],
    61â†’    [/darwin|macos|osx/, "macOS"],
    62â†’    [/windows.*amd64|amd64.*windows|win64/, "Windows x64"],
    63â†’    [/windows.*386|win32/, "Windows x86"],
    64â†’    [/windows/, "Windows"],
    65â†’  ];
    66â†’
    67â†’  // Check if this is a direct binary (archive or executable)
    68â†’  const isArchive = /\.(tar\.gz|tar\.xz|zip|deb|rpm|dmg|msi|exe|pkg|appimage)(\?|$)/i.test(url);
    69â†’
    70â†’  if (isArchive) {
    71â†’    for (const [pattern, label] of platforms) {
    72â†’      if (pattern.test(filename) || pattern.test(url)) {
    73â†’        return { label, isDirect: true };
    74â†’      }
    75â†’    }
    76â†’    // Direct download but platform unknown â€” use filename
    77â†’    const cleanName = (url.split("/").pop() ?? "").split("?")[0];
    78â†’    return { label: cleanName || safeHostname(url), isDirect: true };
    79â†’  }
    80â†’
    81â†’  // Not a direct binary â€” generic link
    82â†’  return { label: safeHostname(url), isDirect: false };
    83â†’}
    84â†’
    85â†’export function SemanticReleaseDetail() {
    86â†’  // Read IDs from URL path â€” useParams() returns stale "0" in static export
    87â†’  const projectId = getPathSegment(1); // /projects/{id}/semantic-releases/{srId}
    88â†’  const srId = getPathSegment(3);
    89â†’  const router = useRouter();
    90â†’  const { data, isLoading } = useSWR(`sr-${srId}`, () => srApi.get(srId));
    91â†’  const { data: projectData } = useSWR(`project-${projectId}`, () =>
    92â†’    projectsApi.get(projectId),
    93â†’  );
    94â†’  const { data: srSourcesData } = useSWR(`sr-sources-${srId}`, () =>
    95â†’    srApi.getSources(srId),
    96â†’  );
    97â†’  const { data: sourcesData } = useSWR(`project-sources-${projectId}`, () =>
    98â†’    sourcesApi.listByProject(projectId),
    99â†’  );
   100â†’  const { data: contextSourcesData } = useSWR(
   101â†’    `project-context-sources-${projectId}`,
   102â†’    () => contextSources.list(projectId),
   103â†’  );
   104â†’
   105â†’  if (isLoading) {
   106â†’    return (
   107â†’      <div className="flex justify-center py-20">
   108â†’        <div
   109â†’          className="text-[13px] text-[#9ca3af]"
   110â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
   111â†’        >
   112â†’          Loading...
   113â†’        </div>
   114â†’      </div>
   115â†’    );
   116â†’  }
   117â†’
   118â†’  const sr = data?.data;
   119â†’  if (!sr) {
   120â†’    return (
   121â†’      <div className="flex justify-center py-20">
   122â†’        <div
   123â†’          className="text-[13px] text-[#9ca3af]"
   124â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
   125â†’        >
   126â†’          Semantic release not found
   127â†’        </div>
   128â†’      </div>
   129â†’    );
   130â†’  }
   131â†’
   132â†’  const project = projectData?.data;
   133â†’  const releasesList = srSourcesData?.data ?? [];
   134â†’  const sourcesList = sourcesData?.data ?? [];
   135â†’  const sourcesById = Object.fromEntries(sourcesList.map((s) => [s.id, s]));
   136â†’  const contextSourcesList = contextSourcesData?.data ?? [];
   137â†’
   138â†’  const handleDelete = async () => {
   139â†’    if (!confirm("Delete this semantic release?")) return;
   140â†’    try {
   141â†’      await srApi.delete(srId);
   142â†’      router.push("/semantic-releases");
   143â†’    } catch {
   144â†’      alert("Failed to delete semantic release.");
