    29â†’// NotifyWorker is a River worker that processes NotifyJobArgs.
    30â†’// It looks up the release, finds all source-level subscriptions, resolves
    31â†’// the notification channel for each, and dispatches via the appropriate sender.
    32â†’// After sending notifications, it checks the project's agent rules and
    33â†’// auto-triggers an agent run if the version criteria are met.
    34â†’type NotifyWorker struct {
    35â†’	river.WorkerDefaults[queue.NotifyJobArgs]
    36â†’	store     NotifyStore
    37â†’	senders   map[string]Sender
    38â†’	publicURL string // base URL for internal Changelogue links (e.g. "https://changelogue.example.com")
    39â†’}
