    50â†’// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
    51â†’func NewNotifyWorker(store NotifyStore, publicURL string) *NotifyWorker {
    52â†’	return &NotifyWorker{
    53â†’		store:     store,
    54â†’		senders:   NewSenders(),
