    59â†’// VersionPassesFilter returns true if the version string passes the source's
    60â†’// include/exclude regex filters. When both are nil the version always passes.
    61â†’func VersionPassesFilter(version string, include, exclude *string) bool {
    62â†’	if include != nil && *include != "" {
    63â†’		matched, err := regexp.MatchString(*include, version)
    64â†’		if err != nil || !matched {
    65â†’			return false
    66â†’		}
    67â†’	}
    68â†’	if exclude != nil && *exclude != "" {
    69â†’		matched, err := regexp.MatchString(*exclude, version)
    70â†’		if err != nil || matched {
    71â†’			return false
    72â†’		}
    73â†’	}
    74â†’	return true
    75â†’}
