   155â†’// checkAgentRules evaluates the project's agent rules against the new release
   156â†’// and the previous release for this source. If any rule matches, an agent run
   157â†’// is enqueued. Errors are logged but do not fail the job â€” notification delivery
   158â†’// is the primary responsibility.
   159â†’func (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, source *models.Source) {
   160â†’	project, err := w.store.GetProject(ctx, source.ProjectID)
   161â†’	if err != nil {
   162â†’		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
