   170â†’			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
   171â†’			return
   172â†’		}
   173â†’	}
   174â†’
   175â†’	// Determine the previous version for comparison.
   176â†’	var previousVersion string
   177â†’	prev, err := w.store.GetPreviousRelease(ctx, source.ID, release.Version)
   178â†’	if err != nil {
   179â†’		slog.Error("get previous release for agent rules", "source_id", source.ID, "err", err)
   180â†’		return
   181â†’	}
   182â†’	if prev != nil {
   183â†’		previousVersion = prev.Version
   184â†’	}
   185â†’
   186â†’	if CheckAgentRules(&rules, release.Version, previousVersion) {
   187â†’		trigger := fmt.Sprintf("auto:version:%s", release.Version)
   188â†’		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger, release.Version); err != nil {
   189â†’			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
   190â†’		} else {
   191â†’			slog.Info("agent run triggered by version rules",
   192â†’				"project_id", source.ProjectID,
   193â†’				"version", release.Version,
   194â†’				"previous_version", previousVersion,
   195â†’			)
   196â†’		}
   197â†’	}
   198â†’}
