   365â†’                  })}
   366â†’                </div>
   367â†’              )}
   368â†’
   369â†’              {/* Download commands as copiable code */}
   370â†’              {downloadCommands.length > 0 && (
   371â†’                <div className="space-y-2">
   372â†’                  {downloadCommands.map((cmd) => (
