	}
	if len(linkParts) > 0 {
		descParts = append(descParts, strings.Join(linkParts, "  â€˘  "))
	}

	description := strings.Join(descParts, "\n\n")
	if len(description) > discordEmbedDescriptionLimit {
		description = description[:discordEmbedDescriptionLimit-3] + "..."
	}

